     1→import React, { FC, useEffect, useMemo, useRef, useState } from 'react';
     2→import { NavigationProp, useFocusEffect, useNavigation } from '@react-navigation/native';
     3→import { Dimensions } from 'react-native';
     4→import { PropsModalizeRef } from '@semparar/design-system-app/src/@types/modelize';
     5→
     6→import { useScreenViewTracking } from '../../hooks/tracking';
     7→import { usePoints } from '../../services';
     8→
     9→import theme from '../../TO_BE_REMOVED/theme';
    10→import { InvoiceCashbackProps } from './models';
    11→import { PropsRootStack } from '../../routes/Models';
    12→import InvoiceCashbackPointsView from './view';
    13→import { eventScreenViewV3, eventSelectContent, eventModalView } from '~/constants/functions';
    14→import {
    15→  getFormattedPoints,
    16→  formatCurrencyBR,
    17→  getParsedCurrency,
    18→  getParsePoints,
    19→} from '../../utils/functions';
    20→
    21→const InvoiceCashbackPoints: FC<InvoiceCashbackProps> = ({ route }) => {
    22→  const {
    23→    points,
    24→    pointsQuantity,
    25→    isLoadingParameterization,
    26→    requestParameterization,
    27→  } = usePoints();
    28→  useScreenViewTracking({ route, title: 'Cashback na fatura' });
    29→  const { height, width } = Dimensions.get('window');
    30→
    31→  useEffect(() => {
    32→    requestParameterization();
    33→  }, []);
    34→
    35→
    36→  const hasFocused = useRef(false);
    37→  useFocusEffect(
    38→    React.useCallback(() => {
    39→      if (!hasFocused.current) {
    40→        eventScreenViewV3('desconto_fatura', 'hub_recompensas_spmais', 'monetizacao', {
    41→          location_1: 'monetizacao',
    42→          location_2: 'hub_recompensas_spmais',
    43→          location_3: 'desconto_fatura',
    44→        });
    45→        hasFocused.current = true;
    46→      }
    47→      return () => {
    48→        hasFocused.current = false;
    49→      };
    50→    }, [])
    51→  );
    52→
    53→  const navigation = useNavigation<NavigationProp<PropsRootStack>>();
    54→
    55→  const conversionFactor = route?.params?.conversionFactor ?? 0;
    56→  const pointsPrice = Number((Math.trunc(points || 0) * conversionFactor).toFixed(2));
    57→
    58→  const finalPrice = pointsPrice || 0;
    59→  const [pointsValue, setPointsValue] = useState('');
    60→  const [reaisValue, setReaisValue] = useState('');
    61→  const [pointsError, setPointsError] = useState(false);
    62→  const [reaisError, setReaisError] = useState(false);
    63→  const convertionPrice = pointsQuantity * conversionFactor;
    64→  const convertionValue = new Intl.NumberFormat('pt-BR', {
    65→    style: 'currency',
    66→    currency: 'BRL',
    67→  }).format(convertionPrice);
    68→
    69→  const handleGoBack = () => {
    70→    navigation.goBack();
    71→  };
    72→
    73→  const handleContinue = () => {
    74→    eventSelectContent({
    75→      content_type: 'cta',
    76→      content_id: 'continuar',
    77→      location_1: 'monetizacao',
    78→      location_2: 'hub_recompensas_spmais',
    79→      location_3: 'desconto_fatura',
    80→    });
    81→
    82→    const reaisValue = conversionFactor * getParsePoints(pointsValue);
    83→
    84→    navigation.navigate('InvoiceCashbackSummary', {
    85→      pointsSelected: getParsePoints(pointsValue),
    86→      reaisSelected: reaisValue,
    87→      conversionFactor,
    88→      productCode: route?.params?.productCode,
    89→      campaingId: route?.params?.campaingId,
    90→    });
    91→  };
    92→
    93→  const invoiceList = (): any[] => {
    94→    const whiteShape = theme.colors.LIGHT_BASE_01;
    95→    const fintechColor = theme.colors.SECONDARY_COLOR_02;
    96→
    97→    return [
    98→      {
    99→        type: 'default',
   100→        icon: 'icon-switch-vertical',
   101→        iconColor: fintechColor,
   102→        iconColorShape: whiteShape,
   103→        description: `Cada ${pointsQuantity.toLocaleString(
   104→          'pt-br'
   105→        )} pontos valem ${convertionValue} no cashback`,
   106→      },
   107→      {
   108→        type: 'default',
   109→        icon: 'icon-calendar',
   110→        iconColor: fintechColor,
   111→        iconColorShape: whiteShape,
   112→        description: 'Você define quanto cashback quer aplicar na sua fatura aberta',
   113→      },
   114→      {
   115→        type: 'default',
   116→        icon: 'icon-payment-invoice',
   117→        iconColor: fintechColor,
   118→        iconColorShape: whiteShape,
   119→        description: 'Se o valor for maior que o da fatura, a diferença será aplicada nas próximas',
   120→      },
   121→      {
   122→        type: 'default',
   123→        icon: 'icon-clock',
   124→        iconColor: fintechColor,
   125→        iconColorShape: whiteShape,
   126→        description: 'O cashback acontece em até 72h',
   127→      },
   128→    ];
   129→  };
   130→  const rate = useMemo(() => {
   131→    if (conversionFactor && conversionFactor > 0) {
   132→      return conversionFactor;
   133→    }
   134→    return 0;
   135→  }, [conversionFactor]);
   136→
   137→  const items = invoiceList
   138→    ? invoiceList().map((item) => ({
   139→        icon: item.icon,
   140→        iconColor: item.iconColor,
   141→        description: item.description,
   142→        iconColorShape: item.iconColorShape,
   143→        type: item.type,
   144→      }))
   145→    : [];
   146→
   147→  const handleChangePoints = (text: string) => {
   148→    const val = getParsePoints(text);
   149→    const formatted = val ? getFormattedPoints(val) : '';
   150→    setPointsValue(formatted);
   151→
   152→    if (rate > 0) {
   153→      setReaisValue(val > 0 ? formatCurrencyBR(val * rate) : '');
   154→    }
   155→    if (val > (Math.trunc(Number(points)) || 0)) {
   156→      setPointsError(true);
   157→    } else {
   158→      setPointsError(false);
   159→    }
   160→  };
   161→
   162→  const handleChangeReais = (text: string) => {
   163→    const val = getParsedCurrency(text);
   164→    const formatted = val > 0 ? formatCurrencyBR(val) : '';
   165→    setReaisValue(formatted);
   166→
   167→    if (rate > 0) {
   168→      const ptsFromReais = Math.round(val / rate);
   169→      setPointsValue(ptsFromReais > 0 ? getFormattedPoints(ptsFromReais) : '');
   170→    }
   171→    if (val > finalPrice) {
   172→      setReaisError(true);
   173→    } else {
   174→      setReaisError(false);
   175→    }
   176→  };
   177→
   178→  const handleUseAll = () => {
   179→    setPointsValue(getFormattedPoints(points || 0));
   180→    setReaisValue(formatCurrencyBR(finalPrice));
   181→    setPointsError(false);
   182→    setReaisError(false);
   183→  };
   184→
   185→  useFocusEffect(
   186→    React.useCallback(() => {
   187→      setPointsValue('');
   188→      setReaisValue('');
   189→      setPointsError(false);
   190→      setReaisError(false);
   191→      return () => {
   192→        setPointsValue('');
   193→        setReaisValue('');
   194→        setPointsError(false);
   195→        setReaisError(false);
   196→      };
   197→    }, [setPointsValue, setReaisValue])
   198→  );
   199→
   200→  const modalizeRef1 = useRef<PropsModalizeRef>(null as unknown as PropsModalizeRef);
   201→
   202→  const onOpenDefault = () => {
   203→    eventSelectContent({
   204→      content_type: 'cta',
   205→      content_id: 'informacoes',
   206→      location_1: 'monetizacao',
   207→      location_2: 'hub_recompensas_spmais',
   208→      location_3: 'desconto_fatura',
   209→    });
   210→
   211→    modalizeRef1.current?.open?.();
   212→
   213→    eventModalView({
   214→      content_id: 'info_desconto_fatura',
   215→      location_1: 'monetizacao',
   216→      location_2: 'hub_recompensas_spmais',
   217→      location_3: 'desconto_fatura',
   218→    });
   219→  };
   220→
   221→  const handleModalizeContinue = () => {
   222→    eventSelectContent({
   223→      content_type: 'cta',
   224→      content_id: 'entendi',
   225→      location_1: 'monetizacao',
   226→      location_2: 'hub_recompensas_spmais',
   227→      location_3: 'info_desconto_fatura',
   228→    });
   229→
   230→    modalizeRef1.current?.close?.();
   231→  };
   232→
   233→  const handleSelectEvent = (contentId: string) => {
   234→    eventSelectContent({
   235→      content_type: 'form',
